import 'package:flutter/material.dart';
import '../../../core/utils/section_keys.dart';class PortfolioNavbar extends StatelessWidget {  final BuildContext scrollContext;  const PortfolioNavbar({super.key, required this.scrollContext});  void _scrollTo(GlobalKey key) {    final context = key.currentContext;    if (context != null) {      Scrollable.ensureVisible(        context,        duration: const Duration(milliseconds: 500),        curve: Curves.easeInOut,      );    }  }  @override  Widget build(BuildContext context) {    return Container(      padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 18),      child: Wrap(        spacing: 12,        runSpacing: 12,        alignment: WrapAlignment.center,        children: [          TextButton(onPressed: () => _scrollTo(SectionKeys.hero), child: const Text('Home')),          TextButton(onPressed: () => _scrollTo(SectionKeys.about), child: const Text('About')),          TextButton(onPressed: () => _scrollTo(SectionKeys.skills), child: const Text('Skills')),          TextButton(onPressed: () => _scrollTo(SectionKeys.services), child: const Text('Services')),          TextButton(onPressed: () => _scrollTo(SectionKeys.projects), child: const Text('Projects')),          TextButton(onPressed: () => _scrollTo(SectionKeys.testimonials), child: const Text('Testimonials')),          TextButton(onPressed: () => _scrollTo(SectionKeys.contact), child: const Text('Contact')),        ],      ),    );  }}